const js = `
(function(){
  const $=(s,r=document)=>r.querySelector(s); const $$=(s,r=document)=>Array.from(r.querySelectorAll(s));
  const canvas=$('#neural-field'); if(canvas){const ctx=canvas.getContext('2d');let w,h,dpr,pts=[];function reset(){dpr=Math.min(devicePixelRatio||1,2);w=canvas.width=innerWidth*dpr;h=canvas.height=innerHeight*dpr;canvas.style.width=innerWidth+'px';canvas.style.height=innerHeight+'px';pts=Array.from({length:Math.min(115,Math.floor(innerWidth/12))},()=>({x:Math.random()*w,y:Math.random()*h,vx:(Math.random()-.5)*.22*dpr,vy:(Math.random()-.5)*.22*dpr,r:(Math.random()*1.7+0.6)*dpr,c:Math.random()}));}function tick(){ctx.clearRect(0,0,w,h);for(const p of pts){p.x+=p.vx;p.y+=p.vy;if(p.x<0||p.x>w)p.vx*=-1;if(p.y<0||p.y>h)p.vy*=-1;ctx.fillStyle=p.c>.75?'rgba(255,240,138,.9)':p.c>.35?'rgba(117,255,215,.8)':'rgba(167,139,255,.75)';ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,7);ctx.fill()}for(let i=0;i<pts.length;i++)for(let j=i+1;j<pts.length;j++){const a=pts[i],b=pts[j],dx=a.x-b.x,dy=a.y-b.y,d=Math.hypot(dx,dy);if(d<150*dpr){ctx.strokeStyle='rgba(117,255,215,'+(0.11*(1-d/(150*dpr)))+')';ctx.lineWidth=1*dpr;ctx.beginPath();ctx.moveTo(a.x,a.y);ctx.lineTo(b.x,b.y);ctx.stroke()}}requestAnimationFrame(tick)}addEventListener('resize',reset,{passive:true});reset();tick();}
  function runCycle(scope=document){const steps=$$('.step',scope);const log=$('[data-run-log]',scope);const score=$('[data-score]',scope);const state=$('[data-state]',scope);const ring=$('[data-ring]',scope);let i=0;if(log)log.textContent='Mission contract committed.';steps.forEach(s=>s.classList.remove('active'));if(score)score.textContent='0';if(state)state.textContent='Running';if(ring)ring.style.strokeDashoffset='301.59';const lines=['Evidence plane mapped.','Claims linked to criteria.','Reviewer boundary preserved.','Acceptance state prepared.','Receipt digest sealed.','Terminal disposition: ready for human authority.'];const t=setInterval(()=>{if(steps[i])steps[i].classList.add('active');if(log)log.textContent+='\\n· '+(lines[i]||'Gate advanced.');const pct=Math.round(((i+1)/steps.length)*100);if(score)score.textContent=String(pct);if(ring)ring.style.strokeDashoffset=String(301.59*(1-pct/100));if(i===steps.length-1){if(state)state.textContent='Ready';clearInterval(t)}i++;},480)}
  $$('[data-run-cycle]').forEach(b=>b.addEventListener('click',e=>{e.preventDefault();runCycle(document)}));
  const scen=$$('.scenario'); scen.forEach(btn=>btn.addEventListener('click',()=>{scen.forEach(s=>s.classList.remove('active'));btn.classList.add('active')}));
  $$('[data-run-coordination]').forEach(b=>b.addEventListener('click',e=>{e.preventDefault();const log=$('[data-coordination-log]');const roles=$$('[data-role]');roles.forEach(r=>r.classList.remove('active'));if(log)log.textContent='Mission class selected. Building role graph.';const lines=['Coordinator selected Planner, Builder, Evidence Scout, Validator, Risk Sentinel, Chronicle, Human Gate.','Work split into bounded jobs; tool permissions remain synthetic.','Proof bundle emitted: trace root, claim matrix, risk ledger, cost ledger.','Verifier mesh rejects unsupported claims and preserves uncertainty.','Chronicle admits accepted synthetic experience only.','Capability package becomes reusable for a harder future mission.'];let i=0;const t=setInterval(()=>{if(roles[i])roles[i].classList.add('active');if(log)log.textContent+='\\n· '+lines[i];i++;if(i>=lines.length)clearInterval(t)},520)}));
  function download(name,obj){const blob=new Blob([JSON.stringify(obj,null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=name;document.body.appendChild(a);a.click();a.remove();setTimeout(()=>URL.revokeObjectURL(a.href),500)}
  $$('[data-download-demo]').forEach(b=>b.addEventListener('click',e=>{e.preventDefault();download('goalos-browser-beta-demo-docket.json',{kind:'GoalOS browser beta synthetic docket',data:'none',valueMoved:0,gates:['commission','submit','map','review','accept','receipt'],receipt:'GOALOS-DEMO-RECEIPT-001'})}));
  $$('[data-download-coordination]').forEach(b=>b.addEventListener('click',e=>{e.preventDefault();download('goalos-proof-gated-coordination-docket.json',{kind:'Proof-gated coordination synthetic docket',data:'none',valueMoved:0,law:'Maximum verified useful work per unit of risk, cost, latency, and proof debt.',roles:['Coordinator','Planner','Builder','Evidence Scout','Validator','Risk Sentinel','Chronicle','Human Gate'],gates:['Mission','Work','Proof','Validation','Decision','Chronicle','Capability']})}));
  $$('[data-docket]').forEach(d=>{const tabs=$$('.docket-tabs button',d);const view=$('[data-docket-view]',d);let data=[];try{data=JSON.parse($('[data-docket-json]',d).textContent)}catch{}tabs.forEach((tab,i)=>tab.addEventListener('click',()=>{tabs.forEach(t=>t.classList.remove('active'));tab.classList.add('active');if(view&&data[i])view.textContent=data[i].body}))});
})();
`;
